datatype ExpansionState = Idle | Walking | CmdSubst | Glob | BraceExpand | Done | Err

class ExpansionOut {
  var buf: seq<int>
  var bounds: seq<int>

  constructor ()
    ensures buf == []
    ensures bounds == []
  {
    buf := [];
    bounds := [];
