}

class Atom {
  var has_glob_expansion: bool

  constructor (hasGlob: bool)
    ensures has_glob_expansion == hasGlob
  {
    has_glob_expansion := hasGlob;
  }
}

class Expansion {
  var node: Atom
  var out: ExpansionOut
  var current_out: seq<int>
  var state: ExpansionState

  constructor (atom: Atom)
    ensures node == atom
    ensures fresh(out)
    ensures out.buf == []
    ensures out.bounds == []
    ensures current_out == []
    ensures state == Idle
  {
    node := atom;
    out := new ExpansionOut();
    current_out := [];
    state := Idle;
  }
}

class LexerOutput {
  var tokens: seq<int>
  var contains_nested: bool

  constructor (tokens_: seq<int>, contains_nested_: bool)
    ensures tokens == tokens_
    ensures contains_nested == contains_nested_
  {
    tokens := tokens_;
    contains_nested := contains_nested_;
  }
}

